            { name: 'Compressor & gas check', desc: 'Compressor current draw and noise checked. Refrigerant pressure assessed for adequacy.' },
            { name: 'Final temperature verification', desc: 'Refrigerator run for 30 minutes after service. Final temperatures measured to confirm cooling improvement.' }
